const items = $input.all().map(i => i.json);
const lang = /[\u0400-\u04FF]/.test(JSON.stringify(items)) ? 'ru' : 'en';

// Collect from all 5 sources by position
const pipelineStatus = items[0] || {};
const topSkills     = items[1] || {};
const trendsData    = items[2] || {};
const profilesData  = items[3] || {};
const vacancyStats  = items[4] || {};

const skillsList = (topSkills.skills || topSkills.data || topSkills).slice(0, 15);
const trends = trendsData.trends || trendsData.data || trendsData;
const profiles = profilesData.profiles || profilesData.data || profilesData;

return [{
  json: {
    pipeline_status: pipelineStatus,
    top_skills: skillsList,
    trends: typeof trends === 'object' && !Array.isArray(trends) ? trends : { trends_list: trends },
    profiles: typeof profiles === 'object' && !Array.isArray(profiles) ? profiles : { list: profiles },
    vacancy_stats: vacancyStats,
    generated_at: new Date().toISOString(),
    user_lang: lang
  }
}];

const provider = $('Build Report Prompt').first().json.llm_provider;
const item = items[0].json;
let raw = provider === 'openai'
  ? (item?.choices?.[0]?.message?.content ?? '')
  : (item?.candidates?.[0]?.content?.parts?.[0]?.text ?? '');
raw = String(raw).replace(/```json|```/g, '').trim();

let report;
try {
  report = JSON.parse(raw);
} catch (e) {
  report = {
    executive_summary: 'Report generation failed — raw LLM output saved.',
    top_skills_analysis: [],
    key_trends: { rising: [], falling: [] },
    profile_highlights: [],
    recommendations: ['Retry report generation'],
    market_insights: ''
  };
}

const baseData = $('Aggregate Report Data').first().json;
return [{
  json: {
    report: report,
    raw_data_summary: {
      skill_count: (baseData.top_skills || []).length,
      profile_count: Object.keys(baseData.profiles || {}).length,
      vacancy_stats: baseData.vacancy_stats
    },
    generated_at: baseData.generated_at,
    user_lang: baseData.user_lang
  }
}];

const r = $json.report;
const lang = $json.user_lang;
const d = new Date($json.generated_at).toLocaleDateString(lang === 'ru' ? 'ru-RU' : 'en-US', { year: 'numeric', month: 'long', day: 'numeric' });

let msg = lang === 'ru'
  ? '<b>📊 Еженедельный отчёт по рынку</b>\n<i>' + d + '</i>\n\n'
  : '<b>📊 Weekly Market Report</b>\n<i>' + d + '</i>\n\n';

msg += '<b>' + (lang === 'ru' ? '📋 Резюме:' : '📋 Executive Summary:') + '</b>\n';
msg += (r.executive_summary || '') + '\n\n';

if (r.key_trends?.rising?.length) {
  msg += '<b>📈 ' + (lang === 'ru' ? 'Растущие навыки:' : 'Rising Skills:') + '</b>\n';
  r.key_trends.rising.slice(0, 5).forEach(t => {
    msg += '  \u2022 <b>' + (t.skill || '') + '</b> ' + (t.change_pct || '') + '% — ' + (t.interpretation || '') + '\n';
  });
  msg += '\n';
}

if (r.key_trends?.falling?.length) {
  msg += '<b>📉 ' + (lang === 'ru' ? 'Падающие навыки:' : 'Falling Skills:') + '</b>\n';
  r.key_trends.falling.slice(0, 5).forEach(t => {
    msg += '  \u2022 <b>' + (t.skill || '') + '</b> ' + (t.change_pct || '') + '% — ' + (t.interpretation || '') + '\n';
  });
  msg += '\n';
}

msg += '<b>🏆 ' + (lang === 'ru' ? 'Топ навыков:' : 'Top Skills:') + '</b>\n';
(r.top_skills_analysis || []).slice(0, 5).forEach((s, i) => {
  msg += '  ' + (i+1) + '. <b>' + (s.skill || '') + '</b> (' + (s.importance_rating || '') + '/10)\n';
});
msg += '\n';

msg += '<b>💡 ' + (lang === 'ru' ? 'Рекомендации:' : 'Recommendations:') + '</b>\n';
(r.recommendations || []).forEach((rec, i) => {
  msg += '  ' + (i+1) + '. ' + rec + '\n';
});

return [{ json: { telegram_html: msg, user_lang: lang, report_json: r, raw_data: $json.raw_data_summary, generated_at: $json.generated_at } }];

const r = $json.report;
const lang = $json.user_lang;
const d = new Date($json.generated_at).toLocaleDateString(lang === 'ru' ? 'ru-RU' : 'en-US', { year: 'numeric', month: 'long', day: 'numeric' });

const title = lang === 'ru' ? 'Еженедельный отчёт по рынку' : 'Weekly Market Report';
const tSummary = lang === 'ru' ? 'Резюме' : 'Executive Summary';
const tRising = lang === 'ru' ? 'Растущие тренды' : 'Rising Trends';
const tFalling = lang === 'ru' ? 'Падающие тренды' : 'Falling Trends';
const tTop = lang === 'ru' ? 'Топ навыков' : 'Top Skills';
const tRec = lang === 'ru' ? 'Рекомендации' : 'Recommendations';
const tInsights = lang === 'ru' ? 'Аналитика рынка' : 'Market Insights';

let html = '<!DOCTYPE html><html><head><meta charset="utf-8"><style>';
html += 'body{font-family:Arial,sans-serif;color:#333;max-width:800px;margin:0 auto;padding:20px}';
html += 'h1{color:#1a73e8;border-bottom:2px solid #1a73e8;padding-bottom:10px}';
html += 'h2{color:#333;margin-top:30px}';
html += 'table{border-collapse:collapse;width:100%;margin:10px 0}';
html += 'th,td{border:1px solid #ddd;padding:8px;text-align:left}';
html += 'th{background:#1a73e8;color:#fff}';
html += 'tr:nth-child(even){background:#f5f5f5}';
html += '.rising{color:#0a0}';
html += '.falling{color:#c00}';
html += '.rec{background:#e8f5e9;border-left:4px solid #4caf50;padding:10px;margin:5px 0}';
html += '.insights{background:#f0f8ff;padding:15px;border-radius:5px}';
html += '</style></head><body>';
html += '<h1>' + title + '</h1>';
html += '<p><em>' + d + '</em></p>';

html += '<h2>' + tSummary + '</h2>';
html += '<p>' + (r.executive_summary || '') + '</p>';

if (r.key_trends?.rising?.length) {
  html += '<h2>' + tRising + '</h2><table><tr><th>Skill</th><th>Change</th><th>Interpretation</th></tr>';
  r.key_trends.rising.forEach(t => {
    html += '<tr><td><b>' + (t.skill || '') + '</b></td><td class="rising">+' + (t.change_pct || '') + '%</td><td>' + (t.interpretation || '') + '</td></tr>';
  });
  html += '</table>';
}

if (r.key_trends?.falling?.length) {
  html += '<h2>' + tFalling + '</h2><table><tr><th>Skill</th><th>Change</th><th>Interpretation</th></tr>';
  r.key_trends.falling.forEach(t => {
    html += '<tr><td><b>' + (t.skill || '') + '</b></td><td class="falling">' + (t.change_pct || '') + '%</td><td>' + (t.interpretation || '') + '</td></tr>';
  });
  html += '</table>';
}

html += '<h2>' + tTop + '</h2><table><tr><th>#</th><th>Skill</th><th>Importance</th><th>Why Relevant</th></tr>';
(r.top_skills_analysis || []).slice(0, 10).forEach((s, i) => {
  html += '<tr><td>' + (i+1) + '</td><td><b>' + (s.skill || '') + '</b></td><td>' + (s.importance_rating || '') + '/10</td><td>' + (s.why_relevant || '') + '</td></tr>';
});
html += '</table>';

html += '<h2>' + tRec + '</h2>';
(r.recommendations || []).forEach(rec => {
  html += '<div class="rec">' + rec + '</div>';
});

if (r.market_insights) {
  html += '<h2>' + tInsights + '</h2>';
  html += '<div class="insights">' + r.market_insights + '</div>';
}

html += '<hr><p style="color:#999;font-size:12px">Generated by SFEDU AI Assistant | ' + new Date().toISOString() + '</p>';
html += '</body></html>';

return [{ json: { email_html: html, email_subject: title + ' — ' + d, generated_at: $json.generated_at } }];
